import{_ as e,o as t,c as l,ag as o}from"./chunks/framework.DUza98OV.js";const c=JSON.parse('{"title":"MySQL 索引设计","description":"","frontmatter":{},"headers":[],"relativePath":"database/mysql-index.md","filePath":"database/mysql-index.md","lastUpdated":1776563785000}'),r={name:"database/mysql-index.md"};function i(n,a,s,d,m,p){return t(),l("div",null,[...a[0]||(a[0]=[o('<h1 id="mysql-索引设计" tabindex="-1">MySQL 索引设计 <a class="header-anchor" href="#mysql-索引设计" aria-label="Permalink to &quot;MySQL 索引设计&quot;">​</a></h1><h2 id="problem" tabindex="-1">Problem <a class="header-anchor" href="#problem" aria-label="Permalink to &quot;Problem&quot;">​</a></h2><p>同一张表数据量上来之后，为什么有的查询依然很快，而有的 SQL 会突然变慢？</p><h2 id="explanation" tabindex="-1">Explanation <a class="header-anchor" href="#explanation" aria-label="Permalink to &quot;Explanation&quot;">​</a></h2><p>索引本质上是在存储层维护一套有序数据结构，MySQL InnoDB 默认使用 B+ 树来支持范围查询和排序。设计索引时，要让查询条件尽量命中联合索引的最左前缀，同时尽可能让查询在索引层完成，减少回表次数。</p><p>如果索引建得过多，会拖慢写入并增加维护成本；如果索引顺序不合理，则即使“建了索引”也不一定被优化器采用。所以索引设计一定要围绕高频查询路径和实际执行计划来做。</p><h2 id="key-points" tabindex="-1">Key Points <a class="header-anchor" href="#key-points" aria-label="Permalink to &quot;Key Points&quot;">​</a></h2><ul><li>联合索引遵循最左前缀原则。</li><li>覆盖索引可以减少回表，提高查询效率。</li><li>索引不是越多越好，写入和存储成本要一并考虑。</li><li>使用 <code>EXPLAIN</code> 验证执行计划，避免纸面优化。</li></ul><h2 id="summary" tabindex="-1">Summary <a class="header-anchor" href="#summary" aria-label="Permalink to &quot;Summary&quot;">​</a></h2><p>好的索引设计是业务查询模式、数据分布和成本权衡的结果。看懂执行计划，比背索引口诀更重要。</p>',10)])])}const u=e(r,[["render",i]]);export{c as __pageData,u as default};
